  1→//! .spc file parser for the pl24r COR24 p-code linker.
  2→//!
  3→//! Parses symbolic p-code assembler text files into a structured AST,
  4→//! including module metadata directives for linking. Language-agnostic:
  5→//! handles .spc files from any compiler targeting the COR24 p-code VM.
  6→
  7→/// A parsed .spc module.
  8→#[derive(Debug, Clone, PartialEq)]
  9→pub struct Module {
 10→    /// Module name (from `.module` directive or inferred from filename).
 11→    pub name: String,
 12→    /// Symbols explicitly exported via `.export`.
 13→    pub exports: Vec<String>,
 14→    /// Symbols declared as external dependencies via `.extern`.
 15→    pub externs: Vec<String>,
 16→    /// Whether this module had explicit `.module`/`.endmodule` metadata.
 17→    pub has_metadata: bool,
 18→    /// The items (procs, globals, data, constants, comments) in order.
 19→    pub items: Vec<Item>,
 20→}
 21→
 22→/// A top-level item in a .spc file.
 23→#[derive(Debug, Clone, PartialEq)]
 24→pub enum Item {
 25→    Proc(Proc),
 26→    Global(Global),
 27→    Data(Data),
 28→    Const(Const),
 29→    Comment(String),
 30→}
 31→
 32→/// A procedure definition (`.proc NAME nlocals` ... `.end`).
 33→#[derive(Debug, Clone, PartialEq)]
 34→pub struct Proc {
 35→    pub name: String,
 36→    pub nlocals: u32,
 37→    pub body: Vec<Statement>,
 38→}
 39→
 40→/// A statement inside a procedure body.
 41→#[derive(Debug, Clone, PartialEq)]
 42→pub enum Statement {
 43→    Label(String),
 44→    Instruction(Instruction),
 45→    Comment(String),
 46→    Blank,
 47→}
 48→
 49→/// A single p-code instruction with optional operand.
 50→#[derive(Debug, Clone, PartialEq)]
 51→pub struct Instruction {
 52→    pub mnemonic: String,
 53→    pub operand: Option<String>,
 54→    pub comment: Option<String>,
 55→}
 56→
 57→/// A global variable declaration (`.global NAME nwords`).
 58→#[derive(Debug, Clone, PartialEq)]
 59→pub struct Global {
 60→    pub name: String,
 61→    pub nwords: u32,
 62→}
 63→
 64→/// A data declaration (`.data NAME byte,byte,...`).
 65→#[derive(Debug, Clone, PartialEq)]
 66→pub struct Data {
 67→    pub name: String,
 68→    pub bytes: Vec<u8>,
 69→}
 70→
 71→/// A constant declaration (`.const NAME value`).
 72→#[derive(Debug, Clone, PartialEq)]
 73→pub struct Const {
 74→    pub name: String,
 75→    pub value: String,
 76→}
 77→
 78→/// Parse error with line number and description.
 79→#[derive(Debug, Clone, PartialEq)]
 80→pub struct ParseError {
 81→    pub line: usize,
 82→    pub message: String,
 83→}
 84→
 85→impl std::fmt::Display for ParseError {
 86→    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
 87→        write!(f, "line {}: {}", self.line, self.message)
 88→    }
 89→}
 90→
 91→impl std::error::Error for ParseError {}
 92→
 93→/// Parse a .spc file's text content into a `Module`.
 94→///
 95→/// `filename` is used to infer the module name when no `.module` directive is present.
 96→pub fn parse(source: &str, filename: &str) -> Result<Module, ParseError> {
 97→    let mut parser = Parser::new(source, filename);
 98→    parser.parse()
 99→}
100→
101→struct Parser<'a> {
102→    lines: Vec<&'a str>,
103→    pos: usize,
104→    filename: &'a str,
105→}
106→
107→impl<'a> Parser<'a> {
108→    fn new(source: &'a str, filename: &'a str) -> Self {
109→        Self {
110→            lines: source.lines().collect(),
111→            pos: 0,
112→            filename,
113→        }
114→    }
115→
116→    fn parse(&mut self) -> Result<Module, ParseError> {
117→        let mut module_name: Option<String> = None;
118→        let mut exports = Vec::new();
119→        let mut externs = Vec::new();
120→        let mut items = Vec::new();
121→        let mut has_metadata = false;
122→        let mut in_module = false;
123→
124→        while self.pos < self.lines.len() {
125→            let line_num = self.pos + 1;
126→            let line = self.lines[self.pos];
127→            let trimmed = line.trim();
128→
129→            if trimmed.is_empty() {
130→                self.pos += 1;
131→                continue;
132→            }
133→
134→            if trimmed.starts_with(';') {
135→                items.push(Item::Comment(trimmed.to_string()));
136→                self.pos += 1;
137→                continue;
138→            }
139→
140→            if let Some(directive) = trimmed.strip_prefix('.') {
141→                let parts: Vec<&str> = directive.splitn(2, char::is_whitespace).collect();
142→                let dir_name = parts[0];
143→                let dir_arg = parts.get(1).map(|s| s.trim());
144→
145→                match dir_name {
146→                    "module" => {
147→                        let name = dir_arg.ok_or_else(|| ParseError {
148→                            line: line_num,
149→                            message: ".module requires a name".to_string(),
150→                        })?;
151→                        // Strip inline comment from module name
152→                        let name = name.split(';').next().unwrap().trim();
153→                        module_name = Some(name.to_string());
154→                        has_metadata = true;
155→                        in_module = true;
156→                        self.pos += 1;
157→                    }
158→                    "endmodule" => {
159→                        if !in_module {
160→                            return Err(ParseError {
161→                                line: line_num,
162→                                message: ".endmodule without matching .module".to_string(),
163→                            });
164→                        }
165→                        in_module = false;
166→                        self.pos += 1;
167→                    }
168→                    "export" => {
169→                        let sym = dir_arg.ok_or_else(|| ParseError {
170→                            line: line_num,
171→                            message: ".export requires a symbol name".to_string(),
172→                        })?;
173→                        let sym = sym.split(';').next().unwrap().trim();
174→                        exports.push(sym.to_string());
175→                        self.pos += 1;
176→                    }
177→                    "extern" => {
178→                        let sym = dir_arg.ok_or_else(|| ParseError {
179→                            line: line_num,
180→                            message: ".extern requires a symbol name".to_string(),
181→                        })?;
182→                        let sym = sym.split(';').next().unwrap().trim();
183→                        externs.push(sym.to_string());
184→                        self.pos += 1;
185→                    }
186→                    "proc" => {
187→                        items.push(Item::Proc(self.parse_proc()?));
188→                    }
189→                    "global" => {
190→                        items.push(Item::Global(self.parse_global()?));
191→                        self.pos += 1;
192→                    }
193→                    "data" => {
194→                        items.push(Item::Data(self.parse_data()?));
195→                        self.pos += 1;
196→                    }
197→                    "const" => {
198→                        items.push(Item::Const(self.parse_const()?));
199→                        self.pos += 1;
200→                    }
201→                    _ => {
202→                        return Err(ParseError {
203→                            line: line_num,
204→                            message: format!("unknown directive: .{dir_name}"),
205→                        });
206→                    }
207→                }
208→            } else {
209→                return Err(ParseError {
210→                    line: line_num,
211→                    message: format!("unexpected line: {trimmed}"),
212→                });
213→            }
214→        }
215→
216→        if in_module {
217→            return Err(ParseError {
218→                line: self.lines.len(),
219→                message: ".module without matching .endmodule".to_string(),
220→            });
221→        }
222→
223→        let name = module_name.unwrap_or_else(|| module_name_from_filename(self.filename));
224→
225→        Ok(Module {
226→            name,
227→            exports,
228→            externs,
229→            has_metadata,
230→            items,
231→        })
232→    }
233→
234→    fn parse_proc(&mut self) -> Result<Proc, ParseError> {
235→        let line_num = self.pos + 1;
236→        let line = self.lines[self.pos].trim();
237→
238→        // .proc NAME nlocals
239→        let rest = line.strip_prefix(".proc").unwrap().trim();
240→        // Strip inline comment
241→        let rest = rest.split(';').next().unwrap().trim();
242→        let parts: Vec<&str> = rest.split_whitespace().collect();
243→
244→        if parts.len() < 2 {
245→            return Err(ParseError {
246→                line: line_num,
247→                message: ".proc requires NAME and nlocals".to_string(),
248→            });
249→        }
250→
251→        let name = parts[0].to_string();
252→        let nlocals: u32 = parts[1].parse().map_err(|_| ParseError {
253→            line: line_num,
254→            message: format!("invalid nlocals: {}", parts[1]),
255→        })?;
256→
257→        self.pos += 1;
258→        let mut body = Vec::new();
259→
260→        while self.pos < self.lines.len() {
261→            let bline = self.lines[self.pos].trim();
262→
263→            if bline == ".end" {
264→                self.pos += 1;
265→                return Ok(Proc {
266→                    name,
267→                    nlocals,
268→                    body,
269→                });
270→            }
271→
272→            if bline.is_empty() {
273→                body.push(Statement::Blank);
274→                self.pos += 1;
275→                continue;
276→            }
277→
278→            if bline.starts_with(';') {
279→                body.push(Statement::Comment(bline.to_string()));
280→                self.pos += 1;
281→                continue;
282→            }
283→
284→            // Label: ends with ':'
285→            if let Some(label) = bline.strip_suffix(':')
286→                && !label.contains(' ') && !label.contains('\t')
287→            {
288→                body.push(Statement::Label(label.to_string()));
289→                self.pos += 1;
290→                continue;
291→            }
292→
293→            // Instruction
294→            body.push(Statement::Instruction(self.parse_instruction(bline)?));
295→            self.pos += 1;
296→        }
297→
298→        Err(ParseError {
299→            line: line_num,
300→            message: format!(".proc {name} missing .end"),
301→        })
302→    }
303→
304→    fn parse_instruction(&self, line: &str) -> Result<Instruction, ParseError> {
305→        // Split off inline comment
306→        let (code, comment) = if let Some(idx) = line.find(';') {
307→            let (c, rest) = line.split_at(idx);
308→            (c.trim(), Some(rest.to_string()))
309→        } else {
310→            (line.trim(), None)
311→        };
312→
313→        let parts: Vec<&str> = code.splitn(2, char::is_whitespace).collect();
314→        let mnemonic = parts[0].to_string();
315→        let operand = parts.get(1).map(|s| s.trim().to_string()).filter(|s| !s.is_empty());
316→
317→        Ok(Instruction {
318→            mnemonic,
319→            operand,
320→            comment,
321→        })
322→    }
323→
324→    fn parse_global(&self) -> Result<Global, ParseError> {
325→        let line_num = self.pos + 1;
326→        let line = self.lines[self.pos].trim();
327→
328→        let rest = line.strip_prefix(".global").unwrap().trim();
329→        let rest = rest.split(';').next().unwrap().trim();
330→        let parts: Vec<&str> = rest.split_whitespace().collect();
331→
332→        if parts.len() < 2 {
333→            return Err(ParseError {
334→                line: line_num,
335→                message: ".global requires NAME and nwords".to_string(),
336→            });
337→        }
338→
339→        let name = parts[0].to_string();
340→        let nwords: u32 = parts[1].parse().map_err(|_| ParseError {
341→            line: line_num,
342→            message: format!("invalid nwords: {}", parts[1]),
343→        })?;
344→
345→        Ok(Global { name, nwords })
346→    }
347→
348→    fn parse_data(&self) -> Result<Data, ParseError> {
349→        let line_num = self.pos + 1;
350→        let line = self.lines[self.pos].trim();
351→
352→        let rest = line.strip_prefix(".data").unwrap().trim();
353→        let rest = rest.split(';').next().unwrap().trim();
354→        let parts: Vec<&str> = rest.splitn(2, char::is_whitespace).collect();
355→
356→        if parts.len() < 2 {
357→            return Err(ParseError {
358→                line: line_num,
359→                message: ".data requires NAME and byte values".to_string(),
360→            });
361→        }
362→
363→        let name = parts[0].to_string();
364→        let bytes: Result<Vec<u8>, _> = parts[1]
365→            .split(',')
366→            .map(|b| {
367→                b.trim().parse::<u8>().map_err(|_| ParseError {
368→                    line: line_num,
369→                    message: format!("invalid byte value: {}", b.trim()),
370→                })
371→            })
372→            .collect();
373→
374→        Ok(Data {
375→            name,
376→            bytes: bytes?,
377→        })
378→    }
379→
380→    fn parse_const(&self) -> Result<Const, ParseError> {
381→        let line_num = self.pos + 1;
382→        let line = self.lines[self.pos].trim();
383→
384→        let rest = line.strip_prefix(".const").unwrap().trim();
385→        let rest = rest.split(';').next().unwrap().trim();
386→        let parts: Vec<&str> = rest.splitn(2, char::is_whitespace).collect();
387→
388→        if parts.len() < 2 {
389→            return Err(ParseError {
390→                line: line_num,
391→                message: ".const requires NAME and value".to_string(),
392→            });
393→        }
394→
395→        Ok(Const {
396→            name: parts[0].to_string(),
397→            value: parts[1].trim().to_string(),
398→        })
399→    }
400→}
401→
402→/// Derive module name from filename: strip path and extension.
403→fn module_name_from_filename(filename: &str) -> String {
404→    let base = filename.rsplit('/').next().unwrap_or(filename);
405→    base.strip_suffix(".spc").unwrap_or(base).to_string()
406→}
