fn test_e2e_runtime_only_error() {
    let out = pl24r()
        .arg(fixture("e2e_runtime.spc"))
        .output()
        .unwrap();

    assert!(!out.status.success());
    let stderr = String::from_utf8_lossy(&out.stderr);
    assert!(stderr.contains("main"));
}

